INSERT IGNORE INTO `quest_offer_reward` (`ID`, `Emote1`, `Emote2`, `Emote3`, `Emote4`, `EmoteDelay1`, `EmoteDelay2`, `EmoteDelay3`, `EmoteDelay4`, `RewardText`, `VerifiedBuild`) VALUES
(29397,0,0,0,0,0,0,0,0,'Aww, it\'s just a stein voucher... Maybe you\'re just playing hard to get.  So here\'s this year\'s stein for you.$b$bBut I suspect I\'ll be seeing a lot more of you.  After all, if you want any Brewfest tokens redeemed, I\'m your girl...$b$bOr maybe I\'m his girl...  $b$bOooohhh... or his...',63305),
(29730,1,0,0,0,0,0,0,0,'So, as you can see, none of this is Riko\'s fault.',63305),
(29731,396,0,0,0,0,0,0,0,'And that\'s how we found our Alliance captive.$b$bBut that\'s not all that happened. Not by a long shot...',63305),
(29743,0,0,0,0,0,0,0,0,'As you look over your sketch, you can\'t help but hope that these creatures don\'t really exist.',63305),
(29823,1,0,0,0,0,0,0,0,'Yeah, I ran away. So blikkin\' what? If it weren\'t for me, Kiryn would be dead. Oh, wait... she\'s already dead... already...$b$bGo away! Riko\'s head hurts.',63305),
(29824,1,0,0,0,0,0,0,0,'The most important thing we learned was that... not only have the Alliance befriended the jinyu, but they\'re giving them weapons, and teaching them how to use them.$b$bThe Alliance now control a force that outnumbers us thirty-to-one. And we - the HORDE - have befriended monkeys.',63305),
(29879,6,273,0,0,0,500,0,0,'Wikket save hozen? And bring slickies?$b$bHmm, maybe wikket not so bad.$b$bTooki Tooki never liked Dook Ookem anyway...',63305),
(29924,4,1,0,0,0,0,0,0,'The dreaded Kher Shan is dead. You have avenged  Ick Ick, Nab Nab, Eet Eet, Bitty Bitty, and the others that Nibi Nibi couldn\'t remember.',63305),
(29933,4,1,94,0,0,500,0,0,'Woot! Woot! Wikket da Ook Dook!',63305),
(29935,396,0,0,0,0,0,0,0,'Hmm.$b$bMean wikkets fighting with nice wikkets?$b$bHozen fight mean wikkets too!',63305),
(29936,396,0,0,0,0,0,0,0,'Impressive work, $n.$b$bIt had not occurred to me that we might somehow befriend these creatures.$b$bWith their acceptance, we can now turn our attention to more important matters.',63305),
(29937,11,1,94,0,0,0,0,0,'Yeah!$b$bNow that\'s the stuff. Just you wait and see...',63305),
(29939,479,1,0,0,0,0,0,0,'We\'ve just revolutionized how these cretins.. err, hozen, feed themselves.$b$bThey\'ll never be the same!',63305),
(29941,396,0,0,0,0,0,0,0,'Good work $n.$b$bThe away team you assembled has departed.$b$bI hope Gorrok had the sense to change out of that ragged red shirt. I admire his patriotism, but he\'s had it on since we left Orgrimmar.$b$bThey won\'t be surprising anyone if he\'s wearing it...',63305),
(29942,4,1,66,0,0,0,0,0,'Now everybody got grub! Great hozen wisdom in Eekle Eekle.$b$bMaybe Eekle Eekle become Chieftain someday...',63305),
(29943,0,0,0,0,0,0,0,0,'Yes!$b$bBy Thrall\'s bloodied fist, I\'ve missed hunting Alliance!',63305),
(29966,396,0,0,0,0,0,0,0,'The Alliance must be purged from this land, $n!$b$bNo half-measures will do!',63305),
(29967,396,0,0,0,0,0,0,0,'I\'d say repelling the attack is an understatement!',63305),
(29968,1,0,0,0,0,0,0,0,'Ah, the smell of progress, and methane. ',63305),
(29971,0,0,0,0,0,0,0,0,'We may have a problem.',63305),
(30015,1,404,1,0,0,500,500,0,'Greetings, $n!$b$bWelcome to Dawn\'s Blossom, a home of my people.$b$bSadly I must depart. Alas, a Lorewalker\'s work is never done.$b$bMake yourself at home. Our people could surely make use of one with your talents.',63305),
(30510,1,0,0,0,0,0,0,0,'Where have you been, $n? Nevermind. As you can see, we survived the battle at the Jade Serpent.$B$BUnfortunately, so did... they.',63305),
(30513,0,0,0,0,0,0,0,0,'Well... we are alive, and that is better than we could have hoped for without your help.\n\nBut, if this is truly to become a base of operations for you, and if we are to join your Horde, there is one more thing you must do to guarantee our security.',63305),
(30515,0,0,0,0,0,0,0,0,'You did it! At the very least, we have justice, and safety, though in the process we have lost so much.\n\nRegardless, it has been decided. We will join the Horde, and with your help, rebuild this village.',63305),
(31121,0,0,0,0,0,0,0,0,'I will help you, traveler, but first I would like to learn a little about this Horde of yours...',63305),
(31132,396,0,0,0,0,0,0,0,'I suppose the best way to explain what a Lorewalker is all about is to show you...',63305),
(31134,396,0,0,0,0,0,0,0,'That is enough translating for one day, I think.$b$bThis experience has been an enlightening one, I hope.',63305),
(31152,1,0,0,0,0,0,0,0,'I am most grateful for the knowledge my forebears have passed on to me.$b$bI stand upon their shoulders.',63305),
(31167,6,0,0,0,0,0,0,0,'Not so different, you and I.$b$bI believe we can become good friends.',63305),
(31239,71,0,0,0,0,0,0,0,'Ha ha! Wikket Grooked ookin\' Jinyu!',63305),
(31241,71,0,0,0,0,0,0,0,'Wikket grookin\' makin\' hozen rich with shinies!$b$b$n makin\' a good second impression. And for hozen, number two is most important!',63305),
(31255,2,1,0,0,0,500,0,0,'Oh, you are a friend of Cho\'s? Welcome! Welcome!$b$bI would serve you a banquet, but as you can see, we are in dire straights at the moment.$b$bSay, would you be willing to lend us a hand?',63305),
(31261,0,0,0,0,0,0,0,0,'Ookin\' grookin, wikket!',63305),
(31393,396,396,6,0,0,500,500,0,'Hello, $c! We have been granted an audience with the White Tiger. The Vale of Eternal Blossoms was recently savaged by our Warchief, and we are arguing that both the Alliance and Horde should be permitted back inside to repair the damage.$b$bThe Vale is a sacred place. I believe my wife Leza saw it in a vision - it\'s what brought my people to Pandaria. We must save it!$b$bDo you think we will be allowed inside?',63305),
(31772,1,0,0,0,0,0,0,0,'Well, it\'s not as much as I would have hoped, but it will have to do. I guess there is no sense in cryin\' over spilled brew.',63305),
(32108,0,0,0,0,0,0,0,0,'<This fire will signal the full might of the Horde invasion fleet to land on this beach, beginning Garrosh\'s campaign in Pandaria.>',63305),
(32190,0,0,0,0,0,0,0,0,'Well met, $c. We are an archaeological expedition, sent to excavate these ruins. We had no idea that this area was crawling with dangerous mogu.',63305),
(32191,0,0,0,0,0,0,0,0,'Ah! Well done! With the guardians gone, we should be able to excavate these ruins safely.',63305),
(32192,0,0,0,0,0,0,0,0,'We blood elves have served the Horde faithfully. Lately, I wonder what we have to gain from Garrosh\'s leadership.',63305),
(32242,0,0,0,0,0,0,0,0,'The Warchief sent you? What does he say?',63305),
(32244,0,0,0,0,0,0,0,0,'Yes, this is remarkable! This is just the kind of artifact that we came here to find!',63305),
(32249,0,0,0,0,0,0,0,0,'You are just in time. The Warchief is about to land. Once this site passes his inspection, the fleet will follow.',63305),
(32250,0,0,0,0,0,0,0,0,'Well done. Our presence here will not be denied!',63305),
(32256,0,0,0,0,0,0,0,0,'What do you have to report?',63305),
(32257,0,0,0,0,0,0,0,0,'Hmm... very interesting. This tablet will yield many secrets, indeed.',63305),
(32284,1,0,0,0,0,0,0,0,'Ah! You received my note. Very good. Vol\'jin is near death, and I will need your help healing his wounds.',63305),
(32318,1,0,0,0,0,0,0,0,'Very good. These should work nicely.',63305),
(32319,1,0,0,0,0,0,0,0,'<Thrall stares at the stone you have handed him.>$b$bVol\'jin\'s hearthstone? My friend, has it come to this?',63305),
(32320,1,0,0,0,0,0,0,0,'Vol\'jin has saved my life many times in the past. To see my own Kor\'kron used against his people cuts deeper than I can put into words.',63305),
(32326,1,1,0,0,0,0,0,0,'$n! So glad Nazgrim selected you.$b$bIt\'s taken a great deal of the Horde\'s effort to get you here through Jaina\'s traps. Maintaining our illusion this close to Darnassus is considerably expensive.$b$bFurthermore, the Sunreavers of Dalaran are risking their neutrality by assisting the Horde with this operation.$b$bIn other words, we expect only the best from you.',63305),
(32327,66,0,0,0,0,0,0,0,'Well executed, $r! I knew we could count on you.$b$bNow to get off this wretched tree.',63305),
(32328,1,1,66,0,0,0,0,0,'You found the bell! And Fanlyr teleported it to Silvermoon for study, as instructed? The Horde will put this to good use.$b$bYou have done the Horde a great service today. Lok\'tar, friend!',63305),
(32329,1,0,0,0,0,0,0,0,'The Warchief \"demands\" progress? His impatience is growing more destructive with each command.$b$bAs it stands, we could use your expertise.',63305),
(32330,1,0,0,0,0,0,0,0,'This reckless use of my people by Garrosh is becoming intolerable. If you had not been here to assist I dread to think what might have happened.',63305),
(32351,0,0,0,0,0,0,0,0,'Well met, $c. You were sent from Domination Point? Very well. We have much to discuss.',63305),
(32352,0,0,0,0,0,0,0,0,'You bested my defenders? Finally, one who can control $Ghis:her; hatred and violence!$B$BI need more $Gmen:women; like you.',63305),
(32363,0,0,0,0,0,0,0,0,'Thank you for coming, $n.',63305),
(32368,0,0,0,0,0,0,0,0,'What did you see, $c?',63305),
(32372,1,0,0,0,0,0,0,0,'The orcs have changed. My Horde has changed. Do I kill my fellow orcs until it is once again \"my\" Horde? Do I have any right to try force the Horde to be what it once was?$b$bThese are troubling times. But for now, I must see to Vol\'jin\'s people.',63305),
(32376,0,0,0,0,0,0,0,0,'Ah, good. You have come. \n\nAgain, I apologize for the cryptic note - but Garrosh is increasingly distrustful of us. I do not want this operation disturbed by hasty action on his part.',63305),
(32378,0,0,0,0,0,0,0,0,'Good. We should be ready to make our move.',63305),
(32379,0,0,0,0,0,0,0,0,'Good. There\'s quite a bit to pore through here... \n\nI will have the Reliquary investigate these. Surely we can use them to discern more of the secrets of these Korune mogu.',63305),
(32384,0,0,0,0,0,0,0,0,'We managed to capture our quarry. \n\nIn truth, though, I am not sure what our next move should be. I will contact the leaders of our allies and see if they have ideas - I don\'t know that our arcane talents are going to pry the secrets of our mogu captive.',63305),
(32391,0,0,0,0,0,0,0,0,'The Alliance beat us here. How could this happen?',63305),
(32392,0,0,0,0,0,0,0,0,'Darnassus, is it?$B$BThe Alliance believes they have won the day. Now, when their arrogance is at its greatest, is our opportunity to pluck the prize from their fingers.',63305),
(32402,2,1,1,0,0,0,0,0,'Good... you\'ve arrived. It\'s not a good day to be Horde in Dalaran.$b$bJaina\'s called for the exile of all the Sunreavers. You and I are going to save as many as we can - including Archmage Aethas Sunreaver himself - and then get out of here as fast as possible.',63305),
(32403,273,0,0,0,0,0,0,0,'Let\'s press on.',63305),
(32448,1,0,0,0,0,0,0,0,'Ah, very good. This is the last thing we needed.',63305),
(39305,1,0,0,0,0,0,0,0,'Thanks to you, the great eagles of Highmountain will live on.$b$bOne of the eggs I thought was too damaged to salvage appears to be hatching...',63796),
(40069,1,0,0,0,0,0,0,0,'Those worm guts will be perfect for a special sort of rope.',63796),
(40070,1,0,0,0,0,0,0,0,'These eggs are in poor condition, $n. Some are cracked and spoiled, while others are cold to the touch.$b$bYet there is still hope. I believe a few of the eggs you recovered can be saved.',63796),
(40071,1,0,0,0,0,0,0,0,'Korgrul deserved his fate. Thank you, $n.',63796),
(40646,1,0,0,0,0,0,0,0,'Excellent choice, $n!$b$bWith the power of that weapon in your hands we will be able to bring balance back to Azeroth.',63704),
(40647,1,0,0,0,0,0,0,0,'I owe you my life, $n. If it wasn\'t for your actions I\'d be dead or worse.$b$bThat traitor, Xavius, may have taken Ursoc but at least we were able to recover the claws. Hope is not lost to us yet.',63834),
(40650,1,0,0,0,0,0,0,0,'I ben tinkin\' for a while, $n. I set aside my walking staff a long time ago for a life of peace, seekin\' to teach da druidic arts in my twilight years.$B$BBut now, war has come to tear my home to shreds, and I can\'t watch that happen.$B$BMy staff and I are ready for another journey with you, $n.',63704),
(40652,1,0,0,0,0,0,0,0,'Greetings, $ct.$b$bThe threats we face are numerous. We must act quickly.',63704),
(40653,1,0,0,0,0,0,0,0,'Yes, I agree. That is a good place to focus our initial efforts.$b$bAs new threats arise, I will bring them to your attention. Elune guide your path, $ct.',63704),
(40654,1,0,0,0,0,0,0,0,'Excellent. Soon enough, the Druids of the Claw will bolster our ranks.',63796),
(40783,0,0,0,0,0,0,0,0,'Well met, champion. $B$BAre you ready for the burden you must bear?',63704),
(40784,0,0,0,0,0,0,0,0,'Valorn...$B$BThat was.. a Dark Rider!$B$BBut how did they reach us here, under the protection of the grove?',63704),
(40785,0,0,0,0,0,0,0,0,'So I was correct, and the Scythe is your quarry.  Know that in order to retrieve it, we must do what no denizen of Duskwood has ever attempted.$B$BWe must hunt the Dark Riders.$B$BI have been tracking them for some time since my encounter with them while hunting down the Wolf Cult.  They are a blight upon these lands, and they hold no right to the artifacts they hoard.$B$BIf we wish to recover this artifact, we will need to find their lair. Fortunately, I may just have the clue we need.',63704),
(40834,0,0,0,0,0,0,0,0,'It\'s strange that the Dark Riders haven\'t followed us here, but I will take whatever boon I can get.$B$BI believe the key to finding the Dark Riders is here somewhere. Let us begin our search.',63704),
(40835,0,0,0,0,0,0,0,0,'Dark energy hums from the journal, which appears to be the writings of Ariden, and chronicles his time in Deadwind Pass. One entry in particular stands out:$B$B\"The Nightbane have become restless of late, and whispers abound that the Scythe of Elune have left Darnassus. It must be coming nearer, for the worgen are constantly drawn to it. They will lead me to it.$B$BThose cursed night elves think the weapon is safe in their care. They will soon find how wrong they are\"',63704),
(40837,0,0,0,0,0,0,0,0,'The worgen appear to be drawn to the catacombs beneath Karazhan.$B$BCould it be...',63704),
(40838,0,0,0,0,0,0,0,0,'Today was a great blow against the Dark Riders, and a victory for the people of Duskwood. $B$BThey are in your debt, as am I.',63704),
(40900,0,0,0,0,0,0,0,0,'The Scythe of Elune!$b$bI never thought I would see that weapon used without turning its wielder into a savage beast, but you\'ve brought balance to its primal nature.$b$bElune has certainly guided your hand, $n. You\'ve accomplished what no druid has done before!',63704),
(41255,1,0,0,0,0,0,0,0,'Excellent. There\'s no time to waste.',63704),
(41332,1,0,0,0,0,0,0,0,'Congratulations, $ct $n.$b$bWe will be counting on you in the days ahead.',63704),
(41468,1,0,0,0,0,0,0,0,'The Claws of Ursoc?$b$bI thought I\'d go the rest of my days without hearing of them again. Is our situation truly so dire? They were sealed away for good reason!',63834),
(41782,4,0,0,0,0,0,0,0,'Excellent! We will need this water to enter the Emerald Dream. I\'ve prepared offerings for Ursol, brother of Ursoc. We will need his help to bypass the magical wards placed upon the claws.\n\nGive me a moment... and let us hope Ursol will aid us.',63834),
(41790,1,0,0,0,0,0,0,0,'You are powerful indeed, but strength alone will not impress me.',63834),
(41791,1,0,0,0,0,0,0,0,'Well done, $n. You handled yourself with honor!$b$bYou\'ve done well so far, yet a single trial remains before I will give you my blessing.',63834),
(41792,1,0,0,0,0,0,0,0,'You have passed every trial I\'ve placed before you and emerged victorious. You are worthy indeed of my brother\'s legacy, and have earned my blessing!$b$bGo, seek out the claws and claim them as your own.',63834),
(41918,0,0,0,0,0,0,0,0,'So, Xavius is behind this. A thousand deaths isn\'t enough of a punishment for that defiler!$b$bBut, you have returned with the claws, that is not an accomplishment that even I could have performed.$b$bYou are truly the hero we need to face the Legion.',63834),
(42031,0,0,0,0,0,0,0,0,'You were just with Naralex? What were the results of the sampling?',63704),
(42032,0,0,0,0,0,0,0,0,'Our champions returned from Shaladrassil just moments ago, Archdruid. The journey was a great success!',63704),
(42033,0,0,0,0,0,0,0,0,'I\'m glad you are here, $n, but if only we had arrived earlier! This place was in chaos when I arrived.$B$BThe survivors claim they were attacked by satyr, but how can this be? No satyrs have roamed these woods since ancient times.',63704),
(42034,0,0,0,0,0,0,0,0,'The satyr have never been this bold, or powerful. They took us completely by surprise, and our magic could not withstand their attacks. Without you, I would not have survived.$B$BI have only one purpose now - to recover that idol.',63704),
(42035,0,0,0,0,0,0,0,0,'Look what we dragged in.',63704),
(42036,0,0,0,0,0,0,0,0,'The Idol... so relieved am I to see it in your hands, $n.$B$BWe will keep it here at the Dreamgrove for safekeeping.',63796),
(42037,0,0,0,0,0,0,0,0,'Good, the druids have gathered. Even now, they should be flocking to Nordrassil to prepare for the ritual.',63796),
(42038,1,66,0,0,0,500,0,0,'I have seen enough of the Nightmare to know that it is not an idle threat. Within its grasp, even the strongest become their own worst enemies.$B$BYou, however, have displayed courage and fortitude even in the face of this great danger. I feel faith that you will lead us to victory against our enemy.$B$B$n, I wish to pledge my loyalty in service of you and the druidic order',63796),
(42039,1,66,0,0,0,500,0,0,'$n, I owe you my life. Your actions gave me a second chance, and it is a chance I have no intention of squandering.$B$BWith your help, we were able to recover the Idol of the Wild. Such a sacred relic would have been a devastating loss had it fallen into the wrong hands.$B$BNow, I will see this journey through to its end.$B$BLet me fight for you. If there is anyone who can defeat the Nightmare, I believe it is you.',63796),
(42040,0,0,0,0,0,0,0,0,'Something isn\'t right here, $n. This isn\'t the Dream. Could Xavius\' creatures have invaded our sanctuary? How did they get past our protective wards?',63834),
(42041,0,0,0,0,0,0,0,0,'Good, I already feel the Nightmare\'s power waning.',63834),
(42042,0,0,0,0,0,0,0,0,'Yay, they\'re saved! Thank you!',63834),
(42043,0,0,0,0,0,0,0,0,'Excellent work, $n. I knew that Elune\'s power could purify the nightmare\'s taint. Her blessing is strong here.',63834),
(42044,0,0,0,0,0,0,0,0,'Today I grieve for a fallen ally, one who has wandered these forests for eons.$B$BHe can now be at peace, knowing he gave his life to protect this sacred place.',63834),
(42045,0,0,0,0,0,0,0,0,'My grandfather, Malorne, the ancient god of the wilds himself... long have I wished for this day, only to find that he is in great peril.$B$BIf he is trapped in the Nightmare, then what hope remains for the rest of us?',64270),
(42046,0,0,0,0,0,0,0,0,'Thank you for all of your heroic efforts, great $c. Without your help, we could not have recovered the Idol and spoken to Malorne himself.$B$BNow that we know he is trapped in the Nightmare, we can devise a plan.',64270),
(42047,1,66,0,0,0,500,0,0,'I have served the wilds for as long as I can remember, mentoring young druids and watching them grow in knowledge and experience.$B$BThere are few who have ascended to the rank of archdruid, but I believe you can become one of our best.$B$BI would be honored to follow your leadership of the grove.',64270),
(42049,0,0,0,0,0,0,0,0,'Excellent. These shards are positively surging with negative energy. Be careful when touching them, $n.',64270),
(42050,0,0,0,0,0,0,0,0,'Well chosen. The others will aid me in defending here. We must hurry.',64270),
(42051,0,0,0,0,0,0,0,0,'Do not be deceived, $n. What appears to be the mountains of Hyjal, is in fact an illusion created by our enemy.$B$BThis is a re-creation of the darkest nightmare in Malorne\'s mind. This is the War of the Ancients, a battle that occurred thousands of years ago.$B$BIt was during this war that Azeroth was first threatened by the Burning Legion, and the War in which Malorne and the Wild Gods fell.',64270),
(42053,0,0,0,0,0,0,0,0,'You lead us to triumph today, $n.',64270),
(42054,0,0,0,0,0,0,0,0,'<Malorne gazes directly at you. Radiant, soothing energy exudes outward from his body. Suddenly, you feel a serene sense of peace and gratitude envelop your entire being.>',64270),
(42055,0,0,0,0,0,0,0,0,'$n, we elders of the Dreamgrove have spoken and all agree. We would like to see you take leadership of the Dreamgrove.$B$BToday, we grant you the title of Arch Druid of the Dreamgrove, a nomination of the highest honor in our order.$B$BWith it, you now carry the responsibility of our order: to protect the wilds! Lead well, $n.',64270),
(42056,1,66,0,0,0,500,0,0,'We have come a long way together, $n. At every step, your choices have led the Dreamgrove to victory.$B$BI would give my life to defend Azeroth, and I know you would do the same.$B$BGreat danger still faces us. $n, take my pledge. We must serve and protect the wilds!',64270),
(42096,1,0,0,0,0,0,0,0,'I\'ve watched you rise up the ranks for a long time, $n. With you leading our order, I know we are in good hands.$B$BCount me as one of your champions, Archdruid.',63704),
(42129,0,0,0,0,0,0,0,0,'Yes, this is it... the pendant of the keepers! Hooray! Vengeance is so fun!',64270),
(42170,0,0,0,0,0,0,0,0,'The Dreamweavers thank you.',64270),
(42234,0,0,0,0,0,0,0,0,'The valarjar thank you.',63834),
(42420,0,0,0,0,0,0,0,0,'The Court of Farondis thanks you.',63834),
(42421,0,0,0,0,0,0,0,0,'The nightfallen thank you.',63834),
(42425,1,0,0,0,0,0,0,0,'I can\'t believe it! I hoped it would work, but I couldn\'t be sure.\n\nYou recovered heirlooms passed down by my family for many generations.\n\nI thought them lost forever.',63796),
(42428,1,0,0,0,0,0,0,0,'Rensar sent you? As much as I\'d like to help, whatever you need is going to have to wait. As you can see, we have bigger problems.$b$bActually, we could really use your help. If you could lend us your aid then I\'ll do all that I can to help you with whatever it is you\'re here for.$b$bWould this be acceptable?',63834),
(42430,1,0,0,0,0,0,0,0,'I\'ve heard from Delandros about how you rescued the Ashen and protected the shrine.$b$bWe all owe you a great deal for your heroism, $n. And it seems that you were able to recover the Fangs as well!$B$BI suspect this war is far from over.',63834),
(42432,1,66,0,0,0,500,0,0,'Finally, we are triumphant, $n! With Xavius\'s defeat, the Nightmare\'s presence will slowly recede from the Emerald Dream.$B$BThe tranquil realm of the sleepers is safe once again. Our druids will work on its restoration and recovery.$B$BThank you, Archdruid $n. Azeroth will see many more serene days and tranquil nights because of you.',64270),
(42438,1,0,0,0,0,0,0,0,'Thank you, $n.$b$bMy heart weeps for those who we\'ve lost this day. The Legion will pay for this, I swear it!',63834),
(42439,1,2,0,0,0,0,0,0,'<Delandros nods.>$b$bThank you, hero. Now that my people are safe we might be able to turn the tide of this battle.',63834),
(42440,1,0,0,0,0,0,0,0,'What? Verstok fled with the Fangs? That fool, he\'s going to get himself killed!',63834),
(42583,0,0,0,0,0,0,0,0,'Good. I know Zen\'tabra and Naralex, and they will serve the Dreamgrove bravely.',63704),
(42584,0,0,0,0,0,0,0,0,'Excellent, $n. Zen\'tabra has done well.',63704),
(42585,0,0,0,0,0,0,0,0,'Well done. I knew that Sister Lilith would come through for us.',63704),
(42586,0,0,0,0,0,0,0,0,'Not only was the mission a success, but our champions recovered an inscribed leaf of ancient knowledge. These may be of great interest to Leafbeard the Storied, the Ancient of Lore who resides to the north.',63704),
(42588,0,0,0,0,0,0,0,0,'Well done! I see that Leafbeard\'s advice has already been useful.',63704),
(42719,1,0,0,0,0,0,0,0,'Oh! Clean water, so pure and magical! Thank you, hero!',64270),
(42758,0,0,0,0,0,0,0,0,'Blimey! This one still has blood on it! Looks like he got a good bite on ye good, lad!',63163),
(42857,396,0,0,0,0,0,0,0,'Ah yes, this is the grell food supply. Perhaps I can use this to lure them away. Thank you.',63704),
(42865,1,0,0,0,0,0,0,0,'I don\'t know if grell have mothers, but I hope that one never kissed his mother with his mouth.',63704),
(42883,603,0,0,0,0,0,0,0,'Thank you, $n. You are welcome in our village anytime.',63704),
(42884,1,0,0,0,0,0,0,0,'The grell trapped our young within the huts. They are no longer at risk, thanks to your generous efforts.',63704),
(43331,517,0,0,0,0,0,0,0,'With the Sixtrigger brothers ended, you\'re finally able to collect your payment for services rendered.$B$BYou rummage through their most prized possessions and take your pick.',63834),
(43365,1,0,0,0,0,0,0,0,'Thank you... it gives Brightwing much peace to know that life continues.',64270),
(43368,1,66,0,0,0,500,0,0,'Your heroic efforts within the Emerald Dream were inspiring, $n. The Dream is safe for now, but it remains threatened as long as Xavius lives.$B$BI will lend you my aid. Together, let us keep Azeroth safe from those who would seek its destruction.',64270),
(43403,0,0,0,0,0,0,0,0,'You have represented the Dreamgrove honorably, Archdruid. Your aid has helped many, and your victories will be spoken of for years to come.',64270),
(43409,4,0,0,0,0,0,0,0,'With this new power, the Legion will fall!',64270),
(43980,1,0,0,0,0,0,0,0,'A sound choice.',63704),
(43991,0,0,0,0,0,0,0,0,'Did you sense the protectors of the wilds? Their presence is ever with us.',63834),
(43995,0,0,0,0,0,0,0,0,'<She hesitates for a moment before accepting the crystals.>',64154),
(44057,0,0,0,0,0,0,0,0,'Yes, its all here, the location of the hunt for Volpin. \n\nI\'m sure there are better uses for a wonderful creature such as he than a pelt on some Noble\'s shoulders, don\'t you agree?',64270),
(44074,0,0,0,0,0,0,0,0,'Thank you, Archdruid.',63834),
(44075,0,0,0,0,0,0,0,0,'Excellent, Arch Druid.',63834),
(44076,0,0,0,0,0,0,0,0,'I am sad to hear of Oakheart\'s demise, but his soul will live on.',63834),
(44077,0,0,0,0,0,0,0,0,'Wonderful. This is exactly what we need.',64270),
(44106,0,0,0,0,0,0,0,0,'Welcome, $n. News of your heroism spreads from the Dreamgrove.',63796),
(44232,1,0,0,0,0,0,0,0,'We are with you, $n.',63796),
(44283,0,0,0,0,0,0,0,0,'Incredible... where did you find these? With these Essences, I will be able to open the way directly to the heart of the Nightmare. Let us make haste!',63834),
(44284,0,0,0,0,0,0,0,0,'Incredible... where did you find these? With these Essences, I will be able to open the way directly to the heart of the Nightmare. Let us make haste!',63834),
(44285,0,0,0,0,0,0,0,0,'Incredible... where did you find these? With these Essences, I will be able to open the way directly to the heart of the Nightmare. Let us make haste!',63834),
(44400,0,0,0,0,0,0,0,0,'Whew. That\'s a SECOND invasion dealt with. Well done.\n\nNow, who do I talk to about getting this place shut down?',64877),
(44431,1,0,0,0,0,0,0,0,'A sound choice.',63834),
(44486,0,0,0,0,0,0,0,0,'Ah, the burns can be reversed with the right alchemic tinctures.$B$BHow interesting.  A formal Darnassian writing style with... demonic affectations.$B$BI suspect I know who penned this.',64270),
(44555,0,0,0,0,0,0,0,0,'Thank you for coming, $p.',63834),
(44563,0,0,0,0,0,0,0,0,'Finally, my long lost brethren can return to this world. Elves belong beneath a starry sky - not a conjured one.$B$BThank you, $p.',63834),
(44789,0,0,0,0,0,0,0,0,'Our victory here is well deserved. With their forces subdued we can press our attacks to the forward camp and the monstrosity on the horizon.',64877),
(45088,0,0,0,0,0,0,0,0,'With these souls returned to the Halls of Valor my forces return to their former strength. As promised, the bounty is yours.',63796),
(45381,0,0,0,0,0,0,0,0,'The power these fragments hold will allow me to call the talisman to us. Well done!',64978),
(45382,0,0,0,0,0,0,0,0,'The power these fragments hold will allow me to call the talisman to us. Well done!',64978),
(45406,0,0,0,0,0,0,0,0,'Today will not be your end, hero. The Legion threatens the Gates of Valor and without the power you wield they will surely fall.',64154),
(45413,1,0,0,0,0,0,0,0,'No... no, no, no, no!$B$BNot good. Not good at all.',64270),
(45414,1,0,0,0,0,0,0,0,'Kruul must not be allowed entrance into this world.',64270),
(45415,0,0,0,0,0,0,0,0,'We must strike before Kruul reaches his full strength, but we\'re going to need help.',64270),
(45417,0,0,0,0,0,0,0,0,'A fitting end.',64877),
(45420,0,0,0,0,0,0,0,0,'With the Eye of Aman\'Thul in our possession, we are one step closer to sealing the portal.',64877),
(45812,0,0,0,0,0,0,0,0,'We must continue our fight.',64877),
(45839,0,0,0,0,0,0,0,0,'Just beyond these cliffs, the forces of the Legion are gathering for their assault. For every moment that passes their number grows.$b$bWe must strike soon before we are overwhelmed!',64154),
(45843,6,0,0,0,0,0,0,0,'Any luck out there?',64270),
(45856,0,0,0,0,0,0,0,0,'You have sacrificed for our lands, brave $c.$B$BYour perseverance has inspired our brothers and sisters to stand against the Burning Legion.',64877),
(45863,0,0,0,0,0,0,0,0,'We hope the increased power to your weapon will prove useful on the Broken Shore and beyond.',64270),
(46110,0,0,0,0,0,0,0,0,'Well done, $n! Well done indeed!$b$bThe Legion will rue the day they set their sights on the land of Stormheim.',64154),
(46244,0,0,0,0,0,0,0,0,'Mephistroth is dead and the Cathedral is secured, but the lower reaches of the Tomb remain in the hands of the Legion.$b$bThis is not the outcome we wanted, but this fight is far from over, $n.$b$bDo not relent. Give the Legion no quarter, no place to hide. When we are ready, we will take the Tomb and drive them from Azeroth!',64270),
(46246,1,1,0,0,0,0,0,0,'I have spent a lifetime hunting the wicked and making them pay for their crimes. When I strike a demon down, I feel a measure of justice has been served.$b$bYou have been an instrument of retribution this day, $ct. Had you walked a different path, you might have made a worthy Warden.',64270),
(46248,1,1,0,0,0,0,0,0,'Step by step, we march closer to victory. We must not relent!$b$bOnly through courage and persistence will we stop the insidious evil that threatens the soul of this world.',64270),
(46250,1,1,0,0,0,0,0,0,'We must take every opportunity to shatter the will of Kil\'jaeden\'s army.$b$bWhen they see their mightiest champions crumble to dust, they will realize that the vaunted Legion is doomed to fall.',64270),
(46252,1,1,0,0,0,0,0,0,'Thinning the ranks of demons in locations like Faronaar and Felsoul Hold cuts the legs out from under the Legion.$b$bKil\'jaeden will fall!',64270),
(46253,396,396,0,0,0,500,0,0,'The Pillars of Creation are in place. The Tomb of Sargeras is sealed, and Aegwynn\'s echo is at rest.$b$b<Khadgar gestures toward the sky.>$b$bUnfortunately, we do not have that luxury.$b$bThough you won a great victory this day, there is no time for revelry. The final battle awaits us. Make ready.',64154),
(46511,0,0,0,0,0,0,0,0,'This is it? You sure you didn\'t find anything else? Like a giant pile of gold on top of a statue made of diamonds which was holding a scroll listing the combination to the vault in Ironforge? That would have been pretty sweet.$B$BOh well. I can make this into a paper weight or throw it at a squirrel.$B$BCome back tomorrow, I\'ll have another job for you.',64270),
(46743,0,0,0,0,0,0,0,0,'Champion, your help to our people has far exceeded any of our expectations, and has provided us some much needed breathing space.\n\nPlease, take these supplies to aid you in the war against the Legion. With your continued aid, we should be able to gather more and prepare them for you.',64978),
(46745,0,0,0,0,0,0,0,0,'Prince Farondis has asked me to thank you for your continued efforts to aid our lands.\n\nPlease take these supplies as a token of our gratitude, and a promise of more to come, should you continue to help us.',64978),
(46746,0,0,0,0,0,0,0,0,'Greetings, little hero.\n\nThe mighty Odyn has proclaimed that you should receive these gifts of war. At every turn you continue to prove your valor and your efforts to aid the Valarjar have not gone unnoticed. \n\nFor the Valarjar! For Odyn! For $n!',64877),
(46747,0,0,0,0,0,0,0,0,'Hero! \n\nYour dedication to defending Val\'sharah has given us a much needed respite from the vile influence of the Legion. We were able to scavenge some supplies as a result of your efforts. \n\nHere, take them and know that, should you continue to aid us, we will set aside more rewards such as these as we find them.',64877),
(46748,0,0,0,0,0,0,0,0,'Outlander, I have some supplies for you. These goods are yours, earned by your continued efforts to our forces here in Suramar.\n\nI shall set aside similar treasures should you choose to aid our people more.\n\nYou have my deepest thanks.',64877),
(46749,0,0,0,0,0,0,0,0,'Your dedication to our efforts has yielded results. We have supplies for you.\n\nContinue your dedication and there will be more.',64978),
(46769,1,1,0,0,0,0,0,0,'Fine work. It\'s important to keep powerful treasures out of demon hands.$b$bThere are more ways to undermine the Legion\'s agenda than simply killing demons... although there\'s a lot to be said for good old-fashioned violence.',64270),
(46777,0,0,0,0,0,0,0,0,'$ct, thanks to your efforts, our forces have been able to secure additional resources from the battlefield.\n\nThe more you continue to dominate the battlefield the more resources our forces can spare.',64978),
(46798,0,0,0,0,0,0,0,0,'Greetings, $ct $n.$b$bFor some time now you have been a paragon to Odyn and a hero to the Valarjar. Our gratitude goes beyond anything mere words can define.$b$bTake these trophies as a token of our gratitude and a share in the spoils of war. The more you aid us, the more we can provide you.',63834),
(46805,0,0,0,0,0,0,0,0,'When we faced the Deceiver, millennia of rage flooded my heart. Hatred took hold, blinding me to every thought but revenge.\n\nThankfully the Light helped me see that the future must not be defined by vengeance, but by hope. Your courage showed me that as well, $n.\n\nIn those last moments of Kil\'jaeden\'s life, I had to let go of the past. Not only for my own sake, but for the memory of my son.\n\nMy spirit and mind are clear and focused. Now we take the fight to Sargeras himself. Now we end the Legion.',64154),
(47023,25,0,0,0,0,0,0,0,'You - I\'ve seen you out on the isles.$B$BWe need to move quickly!',64270),
(47027,0,0,0,0,0,0,0,0,'Thank you for coming. I have something I\'d like to show you.',64270),
(47030,0,0,0,0,0,0,0,0,'Thank you for coming. I have something I\'d like to show you.',64270),
(47034,0,0,0,0,0,0,0,0,'Thank you for coming. I have something I\'d like to show you.',64270),
(47035,0,0,0,0,0,0,0,0,'Thank you for coming. I have something I\'d like to show you.',64270),
(47139,1,1,0,0,0,0,0,0,'Even the mightiest demons unleashed by the Sentinax have fallen before you.$b$bGood. The Legion will be driven from our world, no matter what it takes.',64270),
(47654,2,1,0,0,0,0,0,0,'It is done. My heart mourns the loss of L\'ura, but at least you brought her peace.$b$bOnce the Crown is in place, the Vindicaar will stand against the Legion\'s vile assault. Antorus will fall!',64978),
(47725,0,0,0,0,0,0,0,0,'With the remnants of this seal, we can dispel the wards and enter my sanctum.',64978),
(47726,0,0,0,0,0,0,0,0,'With the remnants of this seal, we can dispel the wards and enter my sanctum.',64978),
(48066,1,1,0,0,0,0,0,0,'Seid willkommen, $n.$b$bMayla zählt Euch zu ihren treuesten Verbündeten. Dank Eurer Gegenwart sollte es möglich sein, sie von den Vorzügen eines Beitritts zur Horde zu überzeugen.',63305),
(48067,1,1,0,0,0,0,0,0,'Die Alten Götter sind für ihre Hinterlist und Falschheit bekannt. Und jetzt dieser direkte Angriff...$b$bWonach auch immer sie suchen... sie wollen es unbedingt.',63305),
(48079,1,1,0,0,0,0,0,0,'Ebenhorn hat uralte Zauberschutze erwähnt, die am Hochberg aufrechterhalten werden müssen. Diese Zauberschutze sollen eine große Finsternis zurückhalten.$b$bDas steht vielleicht im Zusammenhang mit der bösen Macht, die sich seiner bemächtigt hat.$b$bWir müssen darauf hoffen, dass uns Geistwandler Grauhimmel mehr darüber erzählen kann.',63305),
(48202,396,0,0,0,0,0,0,0,'So many demons. So much work to do.',64877),
(48441,0,0,0,0,0,0,0,0,'You have recovered our supplies. As promised, we will aid your forces on Argus.',64877),
(48442,0,0,0,0,0,0,0,0,'Soon, the krokul will raid Nath\'raxas Hold. My people are anxious to begin.',64877),
(48443,0,0,0,0,0,0,0,0,'We were a great civilization, once. But, now?... Thank you, $n. Our combined forces freed many from Nath\'raxas. With fewer slaves, and the Army of the Light on their doorstep, the Legion\'s influence over this region will be greatly diminished.',64877),
(48445,0,0,0,0,0,0,0,0,'Your champions discovered someone living in a cave beneath Oranaar. He is hiding from the Void-Touched, and he appears lucid.',64877),
(48446,0,0,0,0,0,0,0,0,'The voidcallers roaming the Shadowguard Incursion must be extinguished. Your people are sufficiently armed for the coming encounter.',64877),
(48447,0,0,0,0,0,0,0,0,'With L\'ura defeated, and the voidcallers eliminated, the Shadowguard\'s dominance over the city has been crippled. if our campaign against the Legion is successful, there could be a future for the creatures living here.',64877),
(48448,0,0,0,0,0,0,0,0,'Three Legion facilities decimated in a single operation. Extraordinary.',64877),
(48600,0,0,0,0,0,0,0,0,'One step closer to defeating the Legion.',64877),
(48601,0,0,0,0,0,0,0,0,'There\'s nothing more beautiful than a lightburst charge erupting in a Legion stronghold. Your people afforded themselves well.',64877),
(48636,0,0,0,0,0,0,0,0,'Another lightforged to fight alongside your forces.',64978),
(48641,0,0,0,0,0,0,0,0,'The Armies of Legionfall thank you, mate.',64978),
(48654,0,0,0,0,0,0,0,0,'I told the others; I will not abandon my people. I must remain here, but maybe you can help? I have discovered a way to purge the shadow from the void-addled.',64877),
(48668,1,0,0,0,0,0,0,0,'This beacon will be added to the Navigation Console.$b$bA contingent of the Army of the Light will remain to hold this location for future use.',64877),
(48910,0,0,0,0,0,0,0,0,'What say you, offworlder?',64877),
(48911,0,0,0,0,0,0,0,0,'Another soul freed from the cruelty of the void.',64877),
(48912,0,0,0,0,0,0,0,0,'A lightforged soldier can wade through a sea of demons. They will serve you well.',64978),
(48929,396,0,0,0,0,0,0,0,'<Turalyon listens in grim silence.>',64877),
(48954,1,1,0,0,0,0,0,0,'Champion, you have returned... and not a moment too soon.$b$bThe object you hold in your hands is but one of many mysteries unfolding before us.',64877),
(48976,0,0,0,0,0,0,0,0,'$ct, thanks to your efforts, our forces have been able to secure additional resources from the battlefield.\n\nThe more you continue to dominate the battlefield the more resources our forces can spare.',64978),
(48977,0,0,0,0,0,0,0,0,'Archenon poros, champion.\n\nThe Army of the Light wishes to thank you for your aid against the Legion\'s forces on Argus.\n\nPlease accept these supplies with our gratitude. Your continued support brings us ever closer to our ultimate goal of eradicating the Legion once and for all.',64978),
(49015,1,0,0,0,0,0,0,0,'It is finished. At long last, the Burning Crusade is over.$b$bI thank you for all you did, $n. With the power of Argus feeding his Dark Pantheon, Sargeras would have been unstoppable.$b$bOn behalf of the draenei, the eredar, the countless worlds destroyed by the Legion...$b$bThank you.',64877),
(49075,1,1,0,0,0,0,0,0,'Magnificent work!\n\nOnce these runes are integrated into our shielding matrix, the Vindicaar will be able to bypass the Burning Throne\'s defenses and strike directly at the felworks.',64978),
(49076,1,1,0,0,0,0,0,0,'Magnificent work!\n\nOnce these runes are integrated into our shielding matrix, the Vindicaar will be able to bypass the Burning Throne\'s defenses and strike directly at the felworks.',64978),
(49134,1,1,0,0,0,0,0,0,'With these sigils, the Vindicaar can bypass the Burning Throne\'s defenses.$b$bThe time has come to press our advantage and end this war.',64978),
(49293,0,0,0,0,0,0,0,0,'The Legion\'s defeat is at hand.',64978),
(49354,1,0,0,0,0,0,0,0,'Das kam nicht unbedingt unerwartet.',63305),
(49613,0,0,0,0,0,0,0,0,'Gut, wir sind alle da. Unsere Gäste sollten in Kürze eintreffen.',63305),
(49614,0,0,0,0,0,0,0,0,'Und so endet die Geschichte darüber, wie die Nachtgeborenen der Horde beigetreten sind.\n\nIch kann mir nicht vorstellen, wo wir heute ohne Leute wie Oculeth und Thalyssra wären!\n\nWir haben den Nachtgeborenen unser stark verbessertes Teleportationssystem zu verdanken.\n\nVergesst das nie, $n. Wir müssen uns immer daran erinnern, warum wir alle Teil der Horde sind... und bleiben müssen.',63305),
(49756,1,6,0,0,0,0,0,0,'Gute Arbeit, $n. Meine Leute werden ab hier übernehmen.',63305),
(49973,0,0,0,0,0,0,0,0,'Die Stadt Suramar bietet einen prächtigen Anblick. Ich hoffe Silbermond stößt bei ihnen nicht auf Enttäuschung.',63305),
(53720,1,2,0,0,0,0,0,0,'I accept this gesture in the spirit in which it was made, $n.\n\nThe Kul Tirans have been valuable allies, and now we have a physical manifestation of that bond.\n\nI thank you for your continued support of the Alliance. We continue to grow with your aid.',63660),
(53761,1,1,0,0,0,0,0,0,'Ich habe keine Sekunde an Euch gezweifelt.',62876),
(53762,1,1,0,0,0,0,0,0,'Ein weiterer Beweis dafür, dass Ihr und ich gemeinsam Großes erreichen können, $n.\n\nSo viele Möglichkeiten...',62876),
(53763,1,1,0,0,0,0,0,0,'<Talanji lauscht Euren Erzählungen über Xal\'atath und N\'Zoth.>\n\nZandalar hat sich immer noch nich\' ganz vom Befall Uldirs durch den Alten Gott erholt. Wenn sich \'n weiterer erhebt...\n\nDas sind sehr bedrohliche Nachrichten. Diese Flut könn\'n wir nur gemeinsam abwend\'n.',62876),
(54058,1,1,0,0,0,0,0,0,'Lasst Euch nicht ablenken. Es gibt noch viel für uns zu tun.',62876),
(54118,0,0,0,0,0,0,0,0,'Ah... schon viel besser. Wie grausam von Euch, mich in einem solchen Zustand zu belassen!\n\nAber wir können später in Erinnerungen schwelgen. Ihr habt zweifelsohne eine Menge Fragen. Und wie Ihr wisst, biete ich unzählige Antworten.',62876),
(54734,274,0,0,0,0,0,0,0,'I\'m not fond of nobles sticking their nose in my work before it\'s finished. Deal with this.',63660),
(54735,273,0,0,0,0,0,0,0,'This is a fine group you\'ve assembled. Very well done.',63660),
(54851,1,2,0,0,0,0,0,0,'It has been so long since I have seen such a rite performed. I was only a child.\n\nIt means a great deal to me to have had your help in this. Thank you.',63660),
(55499,1,1,273,0,0,300,300,0,'The Age of Order shaped much of Draenor\'s future in many timelines. With each new artifact we find, we learn more about their development and demise, the commonalities and dissonances between each branch.$b$bThis artifact is the most peculiar of all. You did well to bring it to me.',61609),
(56764,4,0,0,0,0,0,0,0,'Well eaten! Every time you win, you\'ll receive a token as a reward. Once you collect five, come back to me and I can award you with a beautiful trophy!',63305),
(57637,1,5,0,0,0,400,0,0,'Oh no, time-locking?! Who knows how long this had been there before we were able to detect it! This is far worse than I had imagined...',62958),
(74376,0,0,0,0,0,0,0,0,'Faszinierend! Ich werde meine Befunde an die anderen Forscher in Valdrakken weitergeben.',63305),
(76425,0,0,0,0,0,0,0,0,'Thank you so much for all that you have done.',64978),
(76531,0,0,0,0,0,0,0,0,'Donate to taverns across the Dragon Isles to cover the tab!',63305),
(76588,0,0,0,0,0,0,0,0,'Fantastische Arbeit, das sind zwei Bedrohungen weniger, um die wir uns kümmern müssen!',63305),
(76997,1,0,0,0,0,0,0,0,'Die Zeit an Eurer Seite ist eine viel bessere Ausbildung als ich diesen Rekruten jemals bieten könnte. Einer von Ihnen wird hier bleiben, um Euch weiterhin zur Seite zu stehen.',63305),
(77095,0,0,0,0,0,0,0,0,'Donate to taverns across the Dragon Isles to cover the tab!',63305),
(77096,0,0,0,0,0,0,0,0,'Donate to taverns across the Dragon Isles to cover the tab!',63305),
(77097,0,0,0,0,0,0,0,0,'Donate to taverns across the Dragon Isles to cover the tab!',63305),
