(29933,0,0,0,0,'Slicky food!',0),
(29937,0,0,0,0,'You didn\'t touch that stuff with your hands did ya?',0),
(29939,0,0,0,0,'I have yet to face a crisis that couldn\'t be fixed with dynamite.',0),
(29942,0,0,0,0,'Wikket grook all them ookin\' snappers?',0),
(29968,0,0,0,0,'Gotta watch out for the wet ones...whewee!',0),
