(41464,0,0,0,0,'Have you stalled their efforts, $r?',64502),
(41782,0,0,0,0,'Did you get the moonwell water? It is essential for our task!',0),
(41790,0,0,0,0,'<The ancient stares at you expectantly.>',63834),
(41791,0,0,0,0,'<The ancient stares at you expectantly.>',63834),
