(41877,0,0,0,0,'Hm?',64502),
(41878,0,0,0,0,'Unless you want a ride, you should keep moving.',64502),
(41893,0,0,0,0,'Is it done, then?',63834),
(42031,0,0,0,0,'I have never seen anything like this...',63834),
(42036,0,0,0,0,'Did you recover the Idol of the Wilds?',0),
(42041,0,0,0,0,'Is it done?',63834),
(42042,0,0,0,0,'Ohhh, the teensy weensy fae dragons are so cute! Are they all right?',63834),
(42043,0,0,0,0,'Did you restore the Dream?',63834),
(42044,0,0,0,0,'No one is safe from the Nightmare.',63834),
(42045,0,0,0,0,'I am glad to see you, $n.',64502),
(42049,0,0,0,0,'How many shards have we collected?',0),
(42050,0,0,0,0,'Have you chosen?',64502),
(42053,0,0,0,0,'',64502),
(42129,0,0,0,0,'Was there much killing?',64502),
(42234,0,0,0,0,'Return to me when you have finished aiding the Valarjar, $n.',63834),
(42420,0,0,0,0,'Return to me when you have finished aiding the Court of Farondis, $n.',63834),
(42422,0,0,0,0,'Return to me when you have finished aiding the Wardens, $n.',64978),
(42425,1,1,0,0,'I have never been particularly fond of heights.',63834),
(42432,0,1,0,0,'Never has the Nightmare spilled into our world. It is our duty to find the root of this evil, and destroy it.',64502),
(42438,0,0,0,0,'Have the Tel\'andu seeds?',63834),
(42439,0,0,0,0,'Did you have any success out there?',63834),
(42440,0,0,0,0,'Did you check on that disturbance?',63834),
(42487,0,0,0,0,'A gift? For me?',64502),
(42719,0,0,0,0,'Poor, poor flowers...',64502),
(42758,0,0,0,0,'I require thirty-three Razor-Sharp Shark Teeth. Do not try to short me, lad.',63305),
(42828,0,0,0,0,'Have you acquired a sufficient sampling?',64502),
